import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); C = int(next(it))
        mx = max(A, B, C)
        d1 = mx - A; d2 = mx - B; d3 = mx - C
        if d1 + d2 + d3 == (d1 | d2 | d3):
            out.append('YES')
        else:
            out.append('NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

